    def evaluate(self, profile_id, planets_data):
        """Evaluate three-planet conjunctions in the same sign for predictions."""
        import logging
        logger = logging.getLogger(__name__)
        try:
            predictions = []
            # Create a dictionary to group planets by sign
            sign_groups = {}
            for planet in planets_data:
                planet_name = planet.get("planet_name")
                sign = planet.get("sign")
                if sign not in sign_groups:
                    sign_groups[sign] = []
                sign_groups[sign].append(planet_name)

            # Check for three-planet conjunctions
            for sign, planets in sign_groups.items():
                if len(planets) >= 3:
                    # Generate all possible triplets
                    for i in range(len(planets)):
                        for j in range(i + 1, len(planets)):
                            for k in range(j + 1, len(planets)):
                                planet_triplet = tuple(sorted([planets[i], planets[j], planets[k]]))
                                if planet_triplet in self.conjunction_matrix:
                                    prediction = self.conjunction_matrix[planet_triplet]
                                    predictions.append({
                                        "prediction_code": prediction["code"],
                                        "text": prediction["text"],
                                        "confidence": prediction["confidence"],
                                        "source_rule": "THREE_PLANET_CONJUNCTION",
                                        "profile_id": profile_id
                                    })
                                    logger.debug(f"Generated prediction: {prediction['code']} for {planet_triplet} in sign {sign}")
            logger.info(f"Generated {len(predictions)} three-planet conjunction predictions for profile {profile_id}")
            return predictions
        except Exception as e:
            logger.error(f"Error evaluating three-planet conjunction rule: {e}")
            raise